const sponsorOrder=["Soluções Outdoor","Genuíno Investments","Magical Earnings Climatização","Casas da Eira","GA.RE Restaurante e Garrafeira","NaturWaterPark","Real Tintas","C.R&N — Investimentos Imobiliários","Irreverent Studio","Restaurante Convívio","Estética Iluminada","Quinta Seara d’Ordens","Casa dos Presuntos","Eletro Ideal","Sandro Oliveira","Ana"];
const sponsorLinks={};
const sponsorName=card=>card.querySelector("p")?.textContent.trim()||"";
const sponsorSlug=name=>name.normalize("NFD").replace(/[\u0300-\u036f]/g,"").replace(/&/g,"e").replace(/[^a-zA-Z0-9]+/g,"-").replace(/^-|-$/g,"").toLowerCase();
function organiseSponsors(){document.querySelectorAll(".sponsor-track").forEach(track=>{const cards=Array.from(track.children);const groups=[];for(let index=0;index<cards.length;index+=sponsorOrder.length){const group=cards.slice(index,index+sponsorOrder.length);group.sort((a,b)=>{const ai=sponsorOrder.indexOf(sponsorName(a));const bi=sponsorOrder.indexOf(sponsorName(b));return(ai<0?999:ai)-(bi<0?999:bi)});groups.push(group)}groups.flat().forEach(card=>track.appendChild(card));cards.forEach(card=>{const name=sponsorName(card);card.dataset.sponsor=sponsorSlug(name);const url=sponsorLinks[name];if(!url||card.querySelector(":scope > a"))return;const link=document.createElement("a");link.href=url;link.target="_blank";link.rel="noopener noreferrer";link.setAttribute("aria-label",`${name} — abrir página`);while(card.firstChild)link.appendChild(card.firstChild);card.appendChild(link)})})}
function createCollectiveStewardsArea(){const section=document.querySelector("#mordomos");const grid=section?.querySelector(".stewards-grid");if(!section||!grid||section.querySelector(".stewards-photo-wall"))return;const title=section.querySelector(".section-heading h2");const intro=section.querySelector(".section-heading > p");if(title)title.textContent="A Comissão.";if(intro)intro.textContent="Um grupo, muitas mãos e uma vontade comum: manter viva a Festa de São Vicente de Paulo.";const wall=document.createElement("div");wall.className="stewards-photo-wall";wall.innerHTML='<h3>Juntos fazemos a festa acontecer.</h3><p>Este será um espaço coletivo, com várias fotografias da Comissão — na preparação, nas atividades e nos dias da Festa — sem destacar ou individualizar nenhum dos seus membros.</p><div class="photo-wall-placeholder">Galeria coletiva da Comissão · fotografias a adicionar</div>';grid.insertAdjacentElement("afterend",wall)}
function applyAdjustments(){organiseSponsors();createCollectiveStewardsArea()}
if(document.readyState==="loading")document.addEventListener("DOMContentLoaded",applyAdjustments);else applyAdjustments();
